INSERT INTO "public"."culture_places" ("id", "title", "description", "category", "date_label", "population", "image_url", "location_link", "created_at", "yer", "longDesc") VALUES ('19d003f4-897e-40a7-9db2-79f0af3fb885', 'Hacı Ahmet Ağa Camii', 'https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html', 'history', null, null, 'https://cdn.kulturenvanteri.com/wp-content/uploads/2023/04/IMG_20230419_155915-scaled.jpg?_gl=1*7pv4l8*_ga*MjAxMjEzMTgxLjE3Njc4NTQwNzc.*_ga_TV1YB45K0M*czE3Njc4NTQwNzckbzEkZzEkdDE3Njc4NTQ2MTIkajMzJGwwJGgw', 'https://www.google.com/maps?q=39.1932335,35.2415123&hl=en&t=h&z=16', '2026-01-04 11:07:30.096695+00', 'Boğazlıyan', 'Boğazlıyan ilçe merkezinde bulunan Hacı Ahmet Ağa Camii Gazi Üniversitesi’nden Prof. Dr. Hakkı Acun’un belirttiğine göre 1719 yılından daha önce yapılmıştır. Cami bir kaç kez onarımdan geçmiş olup, hem cami yapısında hem de minaresinde değişikliklere uğrayarak, bugünkü halini aldı. İlk yapıldığında tek şerefeli olan minare bugün iki şerefelidir. Minarenin birinci şerefeye kadar olan bölümünde dama şeklinde dizilmiş renkli taş dikkat çekiyor. Dikdörtgen planlı, beşik çatılı 11 pencere ile aydınlatılan camide minaredeki damalı süslemeden başka süsleme bulunmuyor. Camiinin iç tavan kısmı üç bölümlü olarak yarım silindirik şekilde ahşaptan yapılmıştır. Ana tavan kısmı taşıyıcı elamanları dört adet ahşap sütundur.

https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html'), ('36c573fc-b6b6-475c-8578-007c79501265', 'Yukarı Mahalle Eski Camii', 'https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html', 'history', 'Hicri 1326', null, 'https://cdn.kulturenvanteri.com/wp-content/uploads/2023/04/IMG_20230419_161848-scaled-e1716907213164.jpg', 'https://maps.app.goo.gl/3rD14jVMEafdrCUB8', '2026-01-04 11:07:30.096695+00', 'Boğazlıyan', 'Cami duvarlarda kesme ve moloz taş, üst örtüde ahşap kullanılarak inşa edilmiştir. Mihraba dikey üç sahınlı olup dikdörtgen planlıdır. Camiye kuzeyde bulunan yedi basamaklı, dikdörtgen formlu, kesme taş basamaklarla çıkılmaktadır. Caminin kuzeyi son cemaat mahalli olarak düzenlenmiştir. Daha önce açık olarak inşa edildiğitahmin edilen son cemaat kısmı sonradan kapanmıştır. Harime çift kanatlı ahşap kapı ile girilmektedir. Girişin üstündeki kitabede üstte Besmele, altta 1326 tarihi yazılıdır. Harim mihraba paralel ahşap ikişer sütunla üç sahına ayrılmıştır. Üst örtü ahşap olup, düz çıtalarla hareketlendirilmiştir.

https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html'), ('8a03a454-d4a8-447c-b9b8-898d8c1c42cf', 'Çarşı Cami Minaresi', 'Boğazlıyan ilçe merkezinde bulunan tarihi Merkez Cami’den günümüze sadece minaresi kalmıştır. 1885-1886 yıllarından önce yapılan tarihi caminin zaman içerisinde yıpranıp, yıkılmaya başlaması üzerine sonraki yıllarda yıkılarak yerine yenisi yapılmıştır. Caminin aynı tarihte yapılan minaresine ise dokunulmamıştır. Üç kademeli, mermer kaplama podyum üzerinde tamamı düzgün kesme taştan ve dikdörtgen prizma formlu bir gövdeye sahip olan yapı, Çarşı Camii’nin bahçesinde ve kuzeydoğusundadır. Tepesinde dışa taşkın profilli bir podyum üzerinde dört sütunçe üzerine küçük bir kubbeli, dört yanı açık bir mimari öğe ile bitirilmiştir. En tepede bir alem yer almaktadır. Gövdesinde küçük aydınlatma pencereleri ve beden duvarlarının orta kısımlarında köşelerde pahlama görülmektedir. Alttaki podyum üzerinde yer alan dikdörtgen formlu girişi, profilli sivri kemer şeklindedir. Minarenin kapısı üzerinde, saçak altında “Sene 1303” yazılı bir kitabesi bulunur.

https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html', 'history', 'Hicri 1303', '215', 'https://cdn.kulturenvanteri.com/wp-content/uploads/2022/04/IMG_20210727_112520-scaled-e1651166080806.jpg', 'https://maps.app.goo.gl/UwCs7GVoZnPdLgrB9', '2026-01-04 11:07:30.096695+00', 'Boğazlıyan', ''), ('8bb8d3a6-2121-4fdb-8b54-732d3b52df3a', 'Hamam', 'Dikdörtgen planlı olup; güney cephesindeki kemerli kapısı önüne, sonradan ahşap giriş bölümü eklenmiştir. Hamam; soyunmalık, ılıklık, sıcaklık ve külhan bölümlerinden oluşmaktadır. Soyunmalık bölümünde sıralı kemerli kasnak üzerine kubbe yeralmaktadır. Kemerli bir geçişle ılıklık bölümüne girilir. Kubbesi kemerle taşınmaktadır ve kubbe üzerinde fil gözleri yer almaktadır.Sıcaklık kısmı yıldızvari planlıdır. Sıcaklık bölümü merkezi bir kubbenin etrafındaki beşik tonozlu altı bölümden oluşmaktadır. Ortada mermer göbektaşı ve duvar kenarlarında mermer kurnalar yer almaktadır. Kuzey bölümü sonradan taşla örülerek sauna oluşturulmuştur.

https://yozgat.ktb.gov.tr/TR-92356/tek-yapilar-ve-anitlar.html', 'history', '', null, 'https://cdn.kulturenvanteri.com/wp-content/uploads/2023/04/IMG_20230419_165252-scaled-e1716907103890.jpg', 'https://maps.app.goo.gl/7aFDv5WYPphGXC7DA', '2026-01-04 11:07:30.096695+00', 'Boğazlıyan', null);